1	//! Built-in dispatch for the Saga 11 model DSL.
2	//!
3	//! `linear(in_dim, out_dim, seed)` creates a fresh `ModelSpec::Linear`
4	//! whose `W` and `b` parameters are stored in the environment under
5	//! generated names. `apply(model_ident, X)` looks up the model and
6	//! evaluates it on the given input.
7	
8	use mlpl_array::{DenseArray, Shape};
9	use mlpl_parser::Expr;
10	use mlpl_trace::Trace;
11	
12	use crate::env::Environment;
13	use crate::error::EvalError;
14	use crate::model::{ActKind, ModelSpec};
15	use crate::value::Value;
16	
17	/// `linear(in_dim, out_dim, seed)`.
18	pub(crate) fn eval_linear(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
19	    if args.len() != 3 {
20	        return Err(EvalError::BadArity {
21	            func: "linear".into(),
22	            expected: 3,
23	            got: args.len(),
24	        });
25	    }
26	    let in_dim = scalar_usize(&args[0], env, "linear")?;
27	    let out_dim = scalar_usize(&args[1], env, "linear")?;
28	    let seed = scalar_f64(&args[2], env, "linear")?;
29	
30	    let id = env.next_model_id;
31	    env.next_model_id += 1;
32	    let w_name = format!("__linear_W_{id}");
33	    let b_name = format!("__linear_b_{id}");
34	
35	    // W <- randn(seed, [in_dim, out_dim]) * 0.5 (Xavier-ish small).
36	    let w_init = mlpl_runtime::call_builtin(
37	        "randn",
38	        vec![
39	            DenseArray::from_scalar(seed),
40	            DenseArray::new(Shape::new(vec![2]), vec![in_dim as f64, out_dim as f64])?,
41	        ],
42	    )?;
43	    let w_data: Vec<f64> = w_init.data().iter().map(|v| v * 0.5).collect();
44	    let w = DenseArray::new(Shape::new(vec![in_dim, out_dim]), w_data)?;
45	    let device = env.device().to_string();
46	    env.set_param(w_name.clone(), w);
47	    env.set_tensor_device(w_name.clone(), device.clone());
48	
49	    let b = DenseArray::zeros(Shape::new(vec![1, out_dim]));
50	    env.set_param(b_name.clone(), b);
51	    env.set_tensor_device(b_name.clone(), device);
52	
53	    Ok(ModelSpec::Linear {
54	        w: w_name,
55	        b: b_name,
56	    })
57	}
58	
59	/// `embed(vocab_size, d_model, seed)` -- token embedding layer.
60	/// Allocates a single `[vocab, d_model]` lookup table parameter,
61	/// initialised with `randn(seed, [vocab, d_model]) * 0.1` (small to
62	/// avoid blowing up early softmax logits in language-model demos).
63	pub(crate) fn eval_embedding(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
64	    if args.len() != 3 {
65	        return Err(EvalError::BadArity {
66	            func: "embed".into(),
67	            expected: 3,
68	            got: args.len(),
69	        });
70	    }
71	    let vocab = scalar_usize(&args[0], env, "embed")?;
72	    let d_model = scalar_usize(&args[1], env, "embed")?;
73	    let seed = scalar_f64(&args[2], env, "embed")?;
74	
75	    let id = env.next_model_id;
76	    env.next_model_id += 1;
77	    let table_name = format!("__embed_E_{id}");
78	
79	    let table_init = mlpl_runtime::call_builtin(
80	        "randn",
81	        vec![
82	            DenseArray::from_scalar(seed),
83	            DenseArray::new(Shape::new(vec![2]), vec![vocab as f64, d_model as f64])?,
84	        ],
85	    )?;
86	    let table_data: Vec<f64> = table_init.data().iter().map(|v| v * 0.1).collect();
87	    let table = DenseArray::new(Shape::new(vec![vocab, d_model]), table_data)?;
88	    let device = env.device().to_string();
89	    env.set_param(table_name.clone(), table);
90	    env.set_tensor_device(table_name.clone(), device);
91	
92	    Ok(ModelSpec::Embedding {
93	        table: table_name,
94	        vocab,
95	        d_model,
96	    })
97	}
98	
99	/// `chain(layer_a, layer_b, ...)`. Each argument must evaluate to a
100	/// `Value::Model`.
101	pub(crate) fn eval_chain(args: &[Expr], env: &mut Environment) -> Result<ModelSpec, EvalError> {
102	    let mut children = Vec::with_capacity(args.len());
103	    for (i, arg) in args.iter().enumerate() {
104	        match crate::eval::eval_expr(arg, env, &mut None)? {
105	            Value::Model(m) => children.push(m),
106	            _ => {
107	                return Err(EvalError::Unsupported(format!(
108	                    "chain: argument {i} did not evaluate to a model"
109	                )));
110	            }
111	        }
112	    }
113	    Ok(ModelSpec::Chain(children))
114	}
115	
116	/// `residual(inner_model)`. Wraps a single model argument in a
