488	) -> Result<(&'static str, Vec<TraceValue>, DenseArray), EvalError> {
489	    let n_arr = eval_expr(count, env, trace)?.into_array()?;
490	    if n_arr.rank() != 0 {
491	        return Err(EvalError::InvalidRepeatCount);
492	    }
493	    let n = n_arr.data()[0] as usize;
494	    let mut losses: Vec<f64> = Vec::with_capacity(n);
495	    let mut last = DenseArray::from_scalar(0.0);
496	    for i in 0..n {
497	        env.set("step".into(), DenseArray::from_scalar(i as f64));
498	        let mut step_val = DenseArray::from_scalar(0.0);
499	        for stmt in body {
500	            step_val = eval_expr(stmt, env, trace)?.into_array()?;
501	        }
502	        // Capture the body's final value as the per-step loss; if it
503	        // is non-scalar (e.g. a vector), reduce by mean for the loss
