1	//! Saga 20 step 003: `argtop_k` + `scatter` array-utility builtins.
2	//!
3	//! These two builtins close the ensemble loop of the Neural
4	//! Thickets workflow: `scatter` accumulates per-variant scores
5	//! into a rank-1 buffer inside a `repeat N { ... }` loop, and
6	//! `argtop_k` picks the K best indices to ensemble.
7	//!
8	//! See `contracts/eval-contract/argtop-k.md` and
9	//! `contracts/eval-contract/scatter.md`.
10	
11	use std::cmp::Ordering;
12	
13	use mlpl_array::{DenseArray, Shape};
14	
15	use crate::error::RuntimeError;
16	
17	/// Dispatch `argtop_k` and `scatter`. Returns `None` when `name` is
18	/// not one of them, so the outer `call_builtin` dispatch chain can
19	/// continue to the next module.
20	pub(crate) fn try_call(
21	    name: &str,
22	    args: Vec<DenseArray>,
23	) -> Option<Result<DenseArray, RuntimeError>> {
24	    match name {
25	        "argtop_k" => Some(builtin_argtop_k(args)),
26	        "scatter" => Some(builtin_scatter(args)),
27	        _ => None,
28	    }
29	}
30	
31	/// `argtop_k(values, k)` -- return the k indices of the largest
32	/// entries in a rank-1 `values` vector. Sorted by descending value,
33	/// ties broken by lower index first (stable).
34	fn builtin_argtop_k(args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
35	    if args.len() != 2 {
36	        return Err(RuntimeError::ArityMismatch {
37	            func: "argtop_k".into(),
38	            expected: 2,
39	            got: args.len(),
40	        });
41	    }
42	    if args[0].rank() != 1 {
43	        return Err(RuntimeError::InvalidArgument {
44	            func: "argtop_k".into(),
45	            reason: format!(
46	                "values must be a rank-1 vector, got rank {}",
47	                args[0].rank()
48	            ),
49	        });
50	    }
51	    if args[1].rank() != 0 {
52	        return Err(RuntimeError::InvalidArgument {
53	            func: "argtop_k".into(),
54	            reason: "k must be a scalar".into(),
55	        });
56	    }
57	    let k_f = args[1].data()[0];
58	    if !k_f.is_finite() || k_f < 0.0 || k_f.fract() != 0.0 {
59	        return Err(RuntimeError::InvalidArgument {
60	            func: "argtop_k".into(),
61	            reason: format!("k must be a non-negative integer, got {k_f}"),
62	        });
63	    }
64	    let k = k_f as usize;
65	    let values = args[0].data();
66	    if k > values.len() {
67	        return Err(RuntimeError::InvalidArgument {
68	            func: "argtop_k".into(),
69	            reason: format!("k = {k} exceeds the vector length {}", values.len()),
70	        });
71	    }
72	    // Stable descending sort by value: tie-break defaults to lower
73	    // original index first because `sort_by` is stable and we pair
74	    // indices with values in ascending-index order before sorting.
75	    let mut indexed: Vec<(usize, f64)> = values.iter().copied().enumerate().collect();
76	    indexed.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(Ordering::Equal));
77	    let out_data: Vec<f64> = indexed.iter().take(k).map(|(i, _)| *i as f64).collect();
78	    Ok(DenseArray::new(Shape::new(vec![k]), out_data)?)
79	}
