81	/// `scatter(buffer, index, value)` -- return a copy of `buffer`
82	/// with the single entry at `index` replaced by `value`.
83	fn builtin_scatter(args: Vec<DenseArray>) -> Result<DenseArray, RuntimeError> {
84	    if args.len() != 3 {
85	        return Err(RuntimeError::ArityMismatch {
86	            func: "scatter".into(),
87	            expected: 3,
88	            got: args.len(),
89	        });
90	    }
91	    if args[0].rank() != 1 {
92	        return Err(RuntimeError::InvalidArgument {
93	            func: "scatter".into(),
94	            reason: format!(
95	                "buffer must be a rank-1 vector, got rank {}",
96	                args[0].rank()
97	            ),
98	        });
99	    }
100	    if args[1].rank() != 0 {
101	        return Err(RuntimeError::InvalidArgument {
102	            func: "scatter".into(),
103	            reason: "index must be a scalar".into(),
104	        });
105	    }
106	    if args[2].rank() != 0 {
107	        return Err(RuntimeError::InvalidArgument {
108	            func: "scatter".into(),
109	            reason: "value must be a scalar".into(),
110	        });
111	    }
112	    let len = args[0].data().len();
113	    let idx_f = args[1].data()[0];
114	    if !idx_f.is_finite() || idx_f < 0.0 || idx_f.fract() != 0.0 {
115	        return Err(RuntimeError::InvalidArgument {
116	            func: "scatter".into(),
117	            reason: format!("index must be a non-negative integer, got {idx_f}"),
118	        });
119	    }
120	    let idx = idx_f as usize;
121	    if idx >= len {
122	        return Err(RuntimeError::InvalidArgument {
123	            func: "scatter".into(),
124	            reason: format!("index {idx} out of bounds for buffer of length {len}"),
125	        });
126	    }
127	    let mut out_data = args[0].data().to_vec();
128	    out_data[idx] = args[2].data()[0];
129	    Ok(DenseArray::new(args[0].shape().clone(), out_data)?)
130	}

