1	//! Saga 14 step 008: Criterion harness comparing the interpreter
2	//! CPU path against the interpreter+`device("mlx") { ... }` path
3	//! on two workloads:
4	//!
5	//! 1. `reshape_reduce_100x100` -- the same 100x100 reshape+reduce
6	//!    program from the step-003 / compile-to-rust harness. Dense
7	//!    matmul-free arithmetic; measures raw dispatch overhead plus
8	//!    MLX's ability to fuse the two axis reductions.
9	//! 2. `tiny_lm_train_step` -- one Adam step (forward + CE +
10	//!    backward + Adam update) on a Saga 13 Tiny-LM-shaped slice
11	//!    scaled down so the bench is interactive: V=60, d=16, T=8,
12	//!    single-head causal attention. Measures the warm-path cost
13	//!    of the full training loop that the end-to-end
14	//!    `demos/tiny_lm_mlx.mlpl` runs 200 of.
15	//!
16	//! Each group runs `interp_cpu` vs `interp_mlx`. Criterion's
17	//! warm-up period (3 s default) amortizes MLX's first-call compile
18	//! overhead; the reported times are warm-path steady-state. The
19	//! first iteration of the outer criterion loop is also timed
20	//! separately as `cold_*` so the Saga 14 plan's "cold vs warm"
21	//! request is satisfied.
22	//!
23	//! Triple-gated to Apple Silicon + the `mlx` feature.
24	//!
25	//! Run with `cargo bench -p mlpl-bench --features mlx`.
26	
27	#![cfg(all(target_os = "macos", target_arch = "aarch64", feature = "mlx"))]
28	
29	use std::time::Instant;
30	
31	use criterion::{Criterion, black_box, criterion_group, criterion_main};
32	
33	use mlpl_eval::{Environment, eval_program};
34	use mlpl_parser::{Expr, lex, parse};
35	
36	const RESHAPE_REDUCE: &str = "m = reshape(iota(10000), [100, 100]); \
37	                              rows = reduce_add(m, 0); \
38	                              cols = reduce_add(m, 1); \
39	                              reduce_add(rows) + reduce_add(cols)";
40	
41	// One Adam step on a Saga 13 Tiny LM-shaped slice. Smaller than
42	// demos/tiny_lm_mlx.mlpl (which is V=280, d=32, T=32, 200 steps)
43	// so a single warm iteration is under a second even on CPU.
44	const TINY_LM_TRAIN_CPU: &str = "\
45	m = chain(embed(60, 16, 0), \
46	          residual(chain(rms_norm(16), causal_attention(16, 1, 1))), \
47	          rms_norm(16), \
48	          linear(16, 60, 2)) ; \
49	X = [1, 3, 5, 7, 2, 4, 6, 0] ; \
50	Y = [3, 5, 7, 2, 4, 6, 0, 1] ; \
51	adam(cross_entropy(apply(m, X), Y), m, 0.001, 0.9, 0.999, 0.00000001)";
52	
53	const TINY_LM_TRAIN_MLX: &str = "\
54	device(\"mlx\") { \
55	  m = chain(embed(60, 16, 0), \
56	            residual(chain(rms_norm(16), causal_attention(16, 1, 1))), \
57	            rms_norm(16), \
58	            linear(16, 60, 2)) \
59	} ; \
60	X = [1, 3, 5, 7, 2, 4, 6, 0] ; \
61	to_device(X, \"mlx\") ; \
62	Y = [3, 5, 7, 2, 4, 6, 0, 1] ; \
63	device(\"mlx\") { \
64	  adam(cross_entropy(apply(m, X), Y), m, 0.001, 0.9, 0.999, 0.00000001) \
65	}";
66	
67	fn parse_or_die(src: &str, label: &str) -> Vec<Expr> {
68	    let tokens = lex(src).unwrap_or_else(|e| panic!("bench lex {label}: {e}"));
69	    parse(&tokens).unwrap_or_else(|e| panic!("bench parse {label}: {e}"))
70	}
71	
72	fn run(stmts: &[Expr]) {
73	    let mut env = Environment::new();
74	    let _ = eval_program(stmts, &mut env).expect("bench eval");
75	}
76	
77	fn cold_time_once(stmts: &[Expr], label: &str) {
78	    // Deliberately untimed-by-criterion cold measurement: print a
79	    // one-shot wall-clock to stdout so the bench output includes
80	    // the MLX-first-call compile overhead next to the warm numbers
81	    // Criterion reports.
82	    let t0 = Instant::now();
83	    run(stmts);
84	    let dt = t0.elapsed();
85	    println!("  cold/{label}: {dt:?}");
86	}
87	
88	fn bench_reshape_reduce(c: &mut Criterion) {
89	    let cpu_src = RESHAPE_REDUCE;
90	    let mlx_src = format!("device(\"mlx\") {{ {RESHAPE_REDUCE} }}");
91	    let cpu_stmts = parse_or_die(cpu_src, "reshape_reduce cpu");
92	    let mlx_stmts = parse_or_die(&mlx_src, "reshape_reduce mlx");
93	
94	    println!("reshape_reduce_100x100 cold timings:");
95	    cold_time_once(&cpu_stmts, "cpu");
96	    cold_time_once(&mlx_stmts, "mlx");
97	
98	    let mut group = c.benchmark_group("reshape_reduce_100x100");
99	    group.bench_function("interp_cpu", |b| {
100	        b.iter(|| {
101	            let mut env = Environment::new();
102	            black_box(eval_program(&cpu_stmts, &mut env).expect("cpu eval"));
103	        });
104	    });
105	    group.bench_function("interp_mlx", |b| {
106	        b.iter(|| {
107	            let mut env = Environment::new();
108	            black_box(eval_program(&mlx_stmts, &mut env).expect("mlx eval"));
109	        });
110	    });
111	    group.finish();
112	}
