            rms_norm(16), \
            linear(16, 60, 2)) \
} ; \
X = [1, 3, 5, 7, 2, 4, 6, 0] ; \
to_device(X, \"mlx\") ; \
Y = [3, 5, 7, 2, 4, 6, 0, 1] ; \
device(\"mlx\") { \
  adam(cross_entropy(apply(m, X), Y), m, 0.001, 0.9, 0.999, 0.00000001) \
}";

