use yew::prelude::*;

pub fn toggle_tutorial(lesson: UseStateHandle<Option<usize>>) -> Callback<web_sys::MouseEvent> {
    Callback::from(move |_| {
        if lesson.is_some() {
            lesson.set(None);
        } else {
            lesson.set(Some(0));
        }
    })
}

pub fn step_lesson(
    lesson: UseStateHandle<Option<usize>>,
    delta: i32,
) -> Callback<web_sys::MouseEvent> {
    Callback::from(move |_| {
        if let Some(cur) = *lesson {
            let next = i32::try_from(cur).unwrap_or(0) + delta;
            if next >= 0 {
                let next_usize = next as usize;
                if next_usize < LESSONS.len() {
                    lesson.set(Some(next_usize));
                }
            }
        }
    })
}

pub fn run_example(
    on_submit: Callback<String>,
    input_value: UseStateHandle<String>,
) -> Callback<String> {
    Callback::from(move |line: String| {
        input_value.set(line.clone());
        on_submit.emit(line);
    })
}

pub struct Lesson {
    pub title: &'static str,
    pub intro: &'static str,
    pub examples: &'static [&'static str],
    pub try_it: &'static str,
}

pub const LESSONS: &[Lesson] = &[
    Lesson {
        title: "Hello Numbers",
        intro: "MLPL starts with simple arithmetic. Numbers are scalars. The four basic operators (+, -, *, /) work as you expect, and parentheses control order of operations.",
        examples: &[
            "1 + 2",
            "3 * 4",
            "10 / 3",
            "2 + 3 * 4",
            "(2 + 3) * 4",
            "-5",
            "-3 + 7",
        ],
        try_it: "Try computing the area of a circle with radius 5: 3.14 * 5 * 5",
    },
    Lesson {
        title: "Arrays",
        intro: "Arrays are MLPL's main data type. Square brackets create a vector. Operators apply element-wise. A scalar is automatically broadcast to match an array's shape.",
        examples: &[
            "[1, 2, 3]",
            "[1, 2, 3] + [4, 5, 6]",
            "[10, 20, 30] - [1, 2, 3]",
            "[1, 2, 3] * 10",
            "100 + [1, 2, 3]",
            "-[1, 2, 3]",
        ],
        try_it: "Create a vector and double every element. Then add 1 to each.",
    },
    Lesson {
        title: "Variables",
        intro: "Bind values to names with =. Variables persist across REPL lines, so you can build up larger computations. Reassignment is allowed.",
        examples: &[
            "x = 42",
            "x + 1",

            "repeat 20 { logits = apply(model, seq); last = last_row(logits); nxt = sample(top_k(last, 20), 0.8, step); seq = concat(seq, nxt) }",
            "decode(tok, seq)",
            "viz_ids = apply_tokenizer(tok, \"the quick\")",
            "attn_w  = attention_weights(model, viz_ids)",
            "svg(attn_w, \"heatmap\")",
        ],
        try_it: "Re-run the repeat 20 { ... } block with a higher temperature (1.5) and a wider top-k (40). Does the generated decode become less repetitive? Then run :experiments to see the recorded tutorial_tiny_lm run.",
    },
    Lesson {
        title: "Running on MLX",
        intro: "Saga 14 adds device(\"target\") { body } so the same source runs on CPU or Apple MLX without edits. Browser WASM is CPU-only, so device(\"mlx\") { ... } is a no-op here (values/shapes still match). On Apple Silicon with `cargo run -p mlpl-repl --features mlx`, matmul/softmax/autograd dispatch through mlpl-mlx. docs/using-mlx.md + docs/benchmarks.md have measured throughput -- step 008 was 0.26x on tiny_lm_train_step, under the 5x gate. Lesson here is source-level parity, not speed.",
        examples: &[
            "device(\"cpu\") { randn(7, [4, 8]) }",
            "device(\"mlx\") { randn(7, [4, 8]) }",
            "device(\"mlx\") { m = linear(4, 3, 0) }",
            "x = reshape(iota(8), [2, 4]) ; to_device(x, \"mlx\")",
            "device(\"mlx\") { apply(m, x) }",
        ],
        try_it: "Build a model outside any device block, then apply(m, X) inside device(\"mlx\") { ... } with to_device(X, \"mlx\"). MLPL raises EvalError::DeviceMismatch naming the op and both sides' devices.",
    },
];

